import machine
import usocket
from umqtt.simple import MQTTClient
import ubinascii
import json
import uselect

# Define WebSocket server address and port
SERVER_HOST = "192.168.1.103"
SERVER_PORT = 8080

# Define IoT device IP and MQTT credentials
DEVICE_IP = "192.168.1.101"
MQTT_BROKER = "broker.hivemq.com"
MQTT_TOPIC = "esp32_control"
MQTT_USER = "your_mqtt_user"
MQTT_PASSWORD = "your_mqtt_password"

class WebSocketServer:
    def __init__(self):
        self.ws_server = None
        self.connections = {}

    def start(self):
        s = usocket.socket(usocket.AF_INET, usocket.SOCK_STREAM)
        s.bind((SERVER_HOST, SERVER_PORT))
        s.listen(5)

        print("WebSocket server started on %s:%d" % (SERVER_HOST, SERVER_PORT))

        while True:
            try:
                conn, addr = s.accept()
                print("New connection from", addr)

                self.connections[conn] = {"ws": None}

                ws = self.connect_ws(conn)
                if ws is not None:
                    self.connections[conn]["ws"] = ws

                data = ws.recv(1024)
                if data:
                    try:
                        json_data = json.loads(data.decode())
                        print(json_data)

                        # Handle JSON command
                        if "action" in json_data and json_data["action"] == "turn_on":
                            self.mqtt_publish("turn_on")
                        elif "action" in json_data and json_data["action"] == "turn_off":
                            self.mqtt_publish("turn_off")

                    except ValueError as e:
                        print(e)

                ws.close()

            except OSError as e:
                print(e)
                conn.close()
                del self.connections[conn]

    def connect_ws(self, conn):
        try:
            ws = usocket.socket(usocket.AF_INET, usocket.SOCK_STREAM)
            ws.settimeout(2)
            addr = (SERVER_HOST, SERVER_PORT + 1)
            ws.connect(addr)

            return ws

        except OSError as e:
            print(e)
            return None

    def mqtt_publish(self, action):
        try:
            client_id = ubinascii.hexlify(machine.unique_id())
            c = MQTTClient(client_id, MQTT_BROKER, user=MQTT_USER, password=MQTT_PASSWORD)

            if action == "turn_on":
                c.publish(MQTT_TOPIC, "{\"action\":\"turn_on\"}")
            elif action == "turn_off":
                c.publish(MQTT_TOPIC, "{\"action\":\"turn_off\"}")

        except OSError as e:
            print(e)


